        adresse: [],
        numeroIFU: [],
        paysId: [],
        paysNom: ['']
      });
    }

    ngOnInit() {
      this.pageTitle = [{
        label: 'cabinets',
        path: '/',
        active: true
      }];
      this.chargerCabinets();
      this.chargerPays();
    }

    ajouter() {
      this.cabinetForm.reset();
      this.formVisible = true;
      this.selectedIndex = null;
    }

    modifier() {
      if (this.selectedIndex !== null) {
        this.formVisible = true;
      }
    }

    supprimer() {
      if (this.selectedIndex !== null) {
        const currentData = this.lignes[this.selectedIndex].value;
        this.cabinetForm.setValue(currentData);
        this.lignes.splice(this.selectedIndex, 1);
        this.selectedIndex = null;
        this.deleteCabinet(currentData);
      }
    }

    fermer() {
      this.formVisible = false;
      this.selectedIndex = null;
      this.cabinetForm.reset();
    }

    selectLigne(index) {
      this.selectedIndex = index;
      const currentData = this.lignes[this.selectedIndex].value;
      this.cabinetForm.setValue(currentData); //console.log(currentData)

      this.selected = currentData;
    }

    enregistrer() {
      if (this.cabinetForm.invalid) {
        this.showWarning('Formulaire invalide');
        return;
      }

      this.isLoading = true;
      const cabinet = this.cabinetForm.value;
      const action$ = this.selected ? this.societeService.updateCabinet(cabinet.id, cabinet) : this.societeService.createCabinet(cabinet);
      action$.subscribe({
        next: () => {
          const msg = this.selected ? 'Modifié' : 'Enregistré';
          this.showSuccess(`${msg} avec succès`);
          this.formVisible = false;
          this.cabinetForm.reset();
          this.loading = false;
          this.selectedIndex = null;
          this.selected = undefined;
          this.lignes = [];
          this.chargerCabinets();
        },
        error: () => {
          this.loading = false;
          this.showError('Erreur serveur !!!');
        }
      });
    }

    chargerCabinets() {
      this.cabinets = [];
      this.societeService.getAllCabinet().subscribe({
        next: data => {
          //console.log(data)
          this.cabinets = data.map(d => this.fb.group({
            id: [d.id],
            nom: [d.nom, Validators.required],
            telephone: [d.telephone],
            email: [d.email],
            adresse: [d.adresse],
            numeroIFU: [d.numeroIFU],
            paysId: [d.paysId],
            paysNom: [d.paysNom]
          }));
          this.lignes = this.cabinets;
          this.result = true;
          this.loading = false;
          this.isLoading = false;
        },
        error: error => {
          console.error('Erreur lors du chargement des cabinets', error);
          this.result = true;
          this.isLoading = false;
          this.loading = false;
          this.showError('Erreur de chargement');
        }
      });
    }

    chargerPays() {
      this.societeService.getAllPays().subscribe({
        next: data => {
          this.pays = data;
